def lambda_handler(event, context):
    """
    Main Lambda handler that processes images uploaded to S3.

    Triggered by S3 PUT events. Reads the uploaded image, processes it,
    stores results back to S3, and sends an SNS notification.

    Args:
        event: S3 event notification payload
        context: Lambda context object

    Returns:
        dict: Processing results summary
    """
    logger.info("Image processor Lambda invoked")
    logger.info(f"Request ID: {context.aws_request_id}")
    logger.debug(f"Event: {json.dumps(event, default=str)}")

    results = []
    errors = []

    # Process each record in the S3 event
    records = event.get('Records', [])
    if not records:
        logger.warning("No records found in event")
        return build_response(400, "No records to process", results, errors)

    for record in records:
        try:
            result = process_record(record, context)
            results.append(result)
            logger.info(f"Successfully processed: {result['source_key']}")
        except UnsupportedImageError as e:
            error_info = {
                'error': str(e),
                'type': 'UnsupportedImageError',
                'record': extract_record_info(record),
            }
            errors.append(error_info)
            logger.warning(f"Unsupported image skipped: {e}")
        except ImageProcessingError as e:
            error_info = {
                'error': str(e),
                'type': 'ImageProcessingError',
                'record': extract_record_info(record),
            }
            errors.append(error_info)
            logger.error(f"Image processing failed: {e}")
        except Exception as e:
            error_info = {
                'error': str(e),
                'type': type(e).__name__,
                'record': extract_record_info(record),
            }
            errors.append(error_info)
            logger.error(f"Unexpected error processing record: {e}", exc_info=True)

    # Send summary notification
    send_summary_notification(results, errors, context)

    response = build_response(200, "Processing complete", results, errors)
    logger.info(f"Processing complete: {len(results)} succeeded, {len(errors)} failed")
    return response


def process_record(record, context):
    """
    Process a single S3 event record.

    Args:
        record: Individual S3 event record
        context: Lambda context object

    Returns:
        dict: Processing result for this record
    """
    # Extract S3 info from the event record
    source_bucket = record['s3']['bucket']['name']
    source_key = unquote_plus(record['s3']['object']['key'])
    object_size = record['s3']['object'].get('size', 0)
    event_time = record.get('eventTime', datetime.utcnow().isoformat())

    logger.info(f"Processing image: s3://{source_bucket}/{source_key} ({object_size} bytes)")

    # Validate file extension
    validate_image_key(source_key)

    # Read the image from S3
    image_data, metadata = read_image_from_s3(source_bucket, source_key)

    # Validate content type
    content_type = metadata.get('ContentType', '')
    if content_type and content_type not in SUPPORTED_CONTENT_TYPES:
        logger.warning(
            f"Content-Type '{content_type}' not in supported list, "
            f"but proceeding based on file extension"
        )

    # Process the image
    processing_result = process_image(image_data, source_key, metadata)

    # Write results back to S3
    results_key = generate_results_key(source_key)
    write_results_to_s3(processing_result, results_key)

    # Send individual notification for this image
    send_image_notification(source_bucket, source_key, results_key, processing_result)

    return {
        'source_bucket': source_bucket,
        'source_key': source_key,
        'results_bucket': RESULTS_BUCKET,
        'results_key': results_key,
        'object_size': object_size,
        'event_time': event_time,
        'processing_result': processing_result,
        'status': 'success',
    }


def validate_image_key(key):
    """
    Validate that the S3 object key represents a supported image file.

    Args:
        key: S3 object key

    Raises:
        UnsupportedImageError: If file extension is not supported
    """
    key_lower = key.lower()
    if not any(key_lower.endswith(ext) for ext in SUPPORTED_EXTENSIONS):
        raise UnsupportedImageError(
            f"Unsupported file type for key '{key}'. "
            f"Supported extensions: {', '.join(sorted(SUPPORTED_EXTENSIONS))}"
        )


def read_image_from_s3(bucket, key):
    """
    Read an image object from S3.

    Args:
        bucket: S3 bucket name
        key: S3 object key

    Returns:
        tuple: (image_bytes, metadata_dict)

    Raises:
        ImageProcessingError: If the image cannot be read from S3
    """
    try:
        logger.debug(f"Reading image from s3://{bucket}/{key}")
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        metadata = {
            'ContentType': response.get('ContentType', ''),
            'ContentLength': response.get('ContentLength', 0),
            'LastModified': str(response.get('LastModified', '')),
            'ETag': response.get('ETag', ''),
            'UserMetadata': response.get('Metadata', {}),
        }
        logger.info(f"Read {len(image_data)} bytes from s3://{bucket}/{key}")
        return image_data, metadata
    except s3_client.exceptions.NoSuchKey:
        raise ImageProcessingError(f"Image not found: s3://{bucket}/{key}")
    except s3_client.exceptions.NoSuchBucket:
        raise ImageProcessingError(f"Bucket not found: {bucket}")
    except Exception as e:
        raise ImageProcessingError(f"Failed to read from S3: {e}")


