def detect_image_format(image_data):
    """
    Detect image format from magic bytes in the file header.

    Args:
        image_data: Raw image bytes

    Returns:
        dict: Detected format information
    """
    if len(image_data) < 12:
        return {'format': 'unknown'}

    # Check magic bytes
    if image_data[:8] == b'\x89PNG\r\n\x1a\n':
        return {'format': 'PNG'}
    elif image_data[:2] == b'\xff\xd8':
        return {'format': 'JPEG'}
    elif image_data[:4] == b'GIF8':
        return {'format': 'GIF'}
    elif image_data[:4] == b'RIFF' and image_data[8:12] == b'WEBP':
        return {'format': 'WEBP'}
    elif image_data[:2] in (b'BM',):
        return {'format': 'BMP'}
    elif image_data[:4] in (b'II\x2a\x00', b'MM\x00\x2a'):
        return {'format': 'TIFF'}
    else:
        return {'format': 'unknown'}


def extract_image_dimensions(image_data, image_format):
    """
    Extract image dimensions from file headers without loading the full image.

    Args:
        image_data: Raw image bytes
        image_format: Detected format string

    Returns:
        tuple: (width, height) or None if unable to extract
    """
    try:
        if image_format == 'PNG' and len(image_data) >= 24:
            # PNG: width and height at bytes 16-23
            width = int.from_bytes(image_data[16:20], byteorder='big')
            height = int.from_bytes(image_data[20:24], byteorder='big')
            return (width, height)
        elif image_format == 'GIF' and len(image_data) >= 10:
            # GIF: width and height at bytes 6-9 (little-endian)
            width = int.from_bytes(image_data[6:8], byteorder='little')
            height = int.from_bytes(image_data[8:10], byteorder='little')
            return (width, height)
        elif image_format == 'BMP' and len(image_data) >= 26:
            # BMP: width and height at bytes 18-25 (little-endian)
            width = int.from_bytes(image_data[18:22], byteorder='little')
            height = abs(int.from_bytes(image_data[22:26], byteorder='little', signed=True))
            return (width, height)
        elif image_format == 'JPEG':
            return extract_jpeg_dimensions(image_data)
        # WEBP and TIFF dimension extraction is more complex; skip for now
        return None
    except Exception as e:
        logger.debug(f"Could not extract dimensions for {image_format}: {e}")
        return None


def extract_jpeg_dimensions(image_data):
    """
    Extract JPEG dimensions by scanning for SOF markers.

    Args:
        image_data: Raw JPEG bytes

    Returns:
        tuple: (width, height) or None
    """
    try:
        i = 2  # Skip SOI marker
        while i < len(image_data) - 9:
            if image_data[i] != 0xFF:
                return None
            marker = image_data[i + 1]
            # SOF markers (0xC0-0xCF except 0xC4 and 0xCC)
            if marker in (0xC0, 0xC1, 0xC2, 0xC3, 0xC5, 0xC6, 0xC7,
                          0xC9, 0xCA, 0xCB, 0xCD, 0xCE, 0xCF):
                height = int.from_bytes(image_data[i + 5:i + 7], byteorder='big')
                width = int.from_bytes(image_data[i + 7:i + 9], byteorder='big')
                return (width, height)
            # Skip this segment
            segment_length = int.from_bytes(image_data[i + 2:i + 4], byteorder='big')
            i += 2 + segment_length
        return None
    except Exception:
        return None


def generate_results_key(source_key):
    """
    Generate the S3 key for storing processing results.

    Args:
        source_key: Original source image S3 key

    Returns:
        str: Results S3 key
    """
    # Strip extension and add timestamp + .json
    base_key = source_key.rsplit('.', 1)[0] if '.' in source_key else source_key
    timestamp = datetime.utcnow().strftime('%Y%m%dT%H%M%SZ')
    results_key = f"results/{base_key}/{timestamp}/result.json"
    return results_key


def write_results_to_s3(results, results_key):
    """
    Write processing results to S3 as a JSON file.

    Args:
        results: Processing results dictionary
        results_key: Destination S3 key

    Raises:
        ImageProcessingError: If writing to S3 fails
    """
    try:
        results_json = json.dumps(results, indent=2, default=str)
        logger.debug(f"Writing results to s3://{RESULTS_BUCKET}/{results_key}")

        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=results_key,
            Body=results_json.encode('utf-8'),
            ContentType='application/json',
            Metadata={
                'processor-version': '1.0.0',
                'source-key': results.get('source_key', 'unknown'),
            }
        )

        logger.info(f"Results written to s3://{RESULTS_BUCKET}/{results_key}")
    except Exception as e:
        raise ImageProcessingError(f"Failed to write results to S3: {e}")


def send_image_notification(source_bucket, source_key, results_key, processing_result):
    """
    Send an SNS notification for an individually processed image.

    Args:
        source_bucket: Source S3 bucket
        source_key: Source S3 key
        results_key: Results S3 key
        processing_result: Processing results dictionary
    """
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return

    try:
        message = {
            'event': 'image_processed',
            'source': f"s3://{source_bucket}/{source_key}",
            'results': f"s3://{RESULTS_BUCKET}/{results_key}",
            'status': processing_result.get('processing_status', 'unknown'),
            'detected_format': processing_result.get('detected_format', 'unknown'),
            'file_size_bytes': processing_result.get('file_size_bytes', 0),
            'processed_at': processing_result.get('processed_at', ''),
        }

        # Include dimensions if available
        if 'width' in processing_result and 'height' in processing_result:
            message['dimensions'] = {
                'width': processing_result['width'],
                'height': processing_result['height'],
            }

        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=f"Image Processed: {source_key}",
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'image_processed',
                },
                'status': {
                    'DataType': 'String',
                    'StringValue': processing_result.get('processing_status', 'unknown'),
                },
            }
        )
        logger.info(f"SNS notification sent for: {source_key}")
    except Exception as e:
        # Don't fail the entire processing just because notification failed
        logger.error(f"Failed to send SNS notification: {e}")


def send_summary_notification(results, errors, context):
    """
    Send a summary SNS notification after processing all records.

    Args:
        results: List of successful processing results
        errors: List of error records
        context: Lambda context object
    """
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping summary notification")
        return

    if not results and not errors:
        return

    try:
        summary = {
            'event': 'processing_batch_complete',
            'request_id': context.aws_request_id,
            'function_name': context.function_name,
            'total_processed': len(results),
            'total_errors': len(errors),
            'timestamp': datetime.utcnow().isoformat() + 'Z',
        }

        if results:
            summary['processed_images'] = [
                {
                    'source_key': r['source_key'],
                    'results_key': r['results_key'],
                    'status': r['status'],
                }
                for r in results
            ]

        if errors:
            summary['error_details'] = [
                {
                    'error': e['error'],
                    'type': e['type'],
                    'record': e.get('record', {}),
                }
                for e in errors
            ]

        subject = (
            f"Image Processing Complete: {len(results)} succeeded, {len(errors)} failed"
        )

        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject max 100 chars
            Message=json.dumps(summary, indent=2, default=str),
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'batch_complete',
                },
                'has_errors': {
                    'DataType': 'String',
                    'StringValue': str(len(errors) > 0).lower(),
                },
            }
        )
        logger.info("Summary notification sent")
    except Exception as e:
        logger.error(f"Failed to send summary notification: {e}")


def extract_record_info(record):
    """
    Safely extract basic info from an S3 event record for error reporting.

    Args:
        record: S3 event record

    Returns:
        dict: Basic record information
    """
    try:
        return {
            'bucket': record.get('s3', {}).get('bucket', {}).get('name', 'unknown'),
            'key': unquote_plus(
                record.get('s3', {}).get('object', {}).get('key', 'unknown')
            ),
        }
    except Exception:
        return {'bucket': 'unknown', 'key': 'unknown'}


def build_response(status_code, message, results, errors):
    """
    Build a standardized response object.

    Args:
        status_code: HTTP-style status code
        message: Human-readable message
        results: List of successful results
        errors: List of errors

    Returns:
        dict: Response object
    """
    return {
        'statusCode': status_code,
        'message': message,
        'summary': {
            'total_processed': len(results),
            'total_errors': len(errors),
            'timestamp': datetime.utcnow().isoformat() + 'Z',
        },
        'results': results,
        'errors': errors,
    }